const AERODROME_BY_CODE = new Map(AERODROMES.map((aerodrome) => [aerodrome.code, aerodrome]));

export function normalizeAerodromeCode(value: string): string {
  return value.trim().toUpperCase().replace(/\s+/g, '');
}

export function findAerodrome(value: string): AerodromeRef | null {
  return AERODROME_BY_CODE.get(normalizeAerodromeCode(value)) ?? null;
}

export function isKnownAerodrome(value: string): boolean {
  return Boolean(findAerodrome(value));
}

export function searchAerodromes(value: string, limit = 12): AerodromeRef[] {
  const query = normalizeAerodromeCode(value);
  if (!query) return AERODROMES.slice(0, limit);
  return AERODROMES
    .filter((aerodrome) => aerodrome.code.includes(query) || aerodrome.name.toUpperCase().includes(query) || aerodrome.cartoName.toUpperCase().includes(query))
    .slice(0, limit);
}
